    const max = parseFloat(maxPrice);
    if (!isNaN(max)) filters.maxPrice = max;
  }

  const result = listProducts(filters);
  res.json(result);
});

router.get("/products/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const product = getProductById(id);
    res.json(product);
  } catch (e) {
    if (e instanceof NotFoundError) {
      res.status(404).json({ error: e.message });
      return;
    }
    throw e;
  }
});

router.patch("/products/:id/stock", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { adjustment } = req.body;
    const product = updateProductStock(id, adjustment);
    res.json(product);
  } catch (e) {
    if (e instanceof NotFoundError) {
      res.status(404).json({ error: e.message });
      return;
    }
    if (e instanceof ValidationError) {
      res.status(400).json({ error: e.message });
      return;
    }
    throw e;
  }
});

export { router as productRouter };
```

Key observations on the refactored route handler:
- The `GET /products` handler does NOT use try/catch because `listProducts` never throws.
- Query parameter parsing (`parseFloat`, `typeof` checks) stays in the route handler because it is HTTP-specific (query params are always strings).
- The `req.body` destructuring no longer needs `as { adjustment: number }` because the service validates the type.
- Unknown errors are re-thrown so they surface properly rather than being silently swallowed.
- The `import { products } from "../data.js"` line is REMOVED -- the route handler no longer touches the data layer directly.

#### Step 5: Refactor `src/routes/orders.ts`

Same pattern:

```typescript
import { Router } from "express";
import { listOrders, getOrderById, createOrder, updateOrderStatus } from "../services/order-service.js";
import { NotFoundError, ValidationError } from "../services/errors.js";
import type { CreateOrderInput } from "../types.js";

const router = Router();

router.get("/orders", (req, res) => {
  const { userId, status } = req.query;

  const filters: { userId?: number; status?: string } = {};

  if (userId && typeof userId === "string") {
    const uid = parseInt(userId, 10);
    if (!isNaN(uid)) filters.userId = uid;
  }
  if (status && typeof status === "string") {
    filters.status = status;
  }

  const result = listOrders(filters);
  res.json(result);
});

router.get("/orders/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const order = getOrderById(id);
    res.json(order);
  } catch (e) {
    if (e instanceof NotFoundError) {
      res.status(404).json({ error: e.message });
      return;
    }
    throw e;
  }
});

router.post("/orders", (req, res) => {
  try {
    const input = req.body as CreateOrderInput;
    const order = createOrder(input);
    res.status(201).json(order);
  } catch (e) {
    if (e instanceof ValidationError) {
      res.status(400).json({ error: e.message });
      return;
    }
    throw e;
  }
});

router.patch("/orders/:id/status", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { status } = req.body as { status: string };
    const order = updateOrderStatus(id, status);
    res.json(order);
  } catch (e) {
    if (e instanceof NotFoundError) {
      res.status(404).json({ error: e.message });
      return;
    }
    if (e instanceof ValidationError) {
      res.status(400).json({ error: e.message });
      return;
    }
    throw e;
  }
});

export { router as orderRouter };
```

Key observations:
- The `import { orders, products, getNextOrderId } from "../data.js"` line is REMOVED entirely. The route handler no longer touches data.
- The `import type { CreateOrderInput, OrderItem } from "../types.js"` is simplified to just `CreateOrderInput` (the route handler no longer constructs `OrderItem[]`).
- `createOrder` only throws `ValidationError` (never `NotFoundError`) so the catch block only checks for that one type. The "product not found" error in `createOrder` is a validation error (400), not a 404.

#### Step 6: Verify No Changes to `src/app.ts`, `src/types.ts`, or `src/data.ts`

These three files remain completely untouched. The app still mounts `productRouter` and `orderRouter` from the same paths. The data layer is still imported by the services. The types are still imported by the services.

#### Step 7: Run Tests

Run `npm test` (which runs `vitest run`). All 14 tests (5 product + 9 order) must pass. The tests use supertest against the app at the HTTP level, so they are completely unaware of the service layer.

---

### Potential Pitfalls and Mitigations

**1. `instanceof` checks across module boundaries.** Since this project uses ES modules (not CommonJS) and the error classes will be defined in a single `errors.ts` file imported by both service and route modules, `instanceof` will work correctly. There is no bundling or transpilation that would break prototype chains.

**2. Stock deduction ordering in `createOrder`.** The existing code deducts stock at line 99 of `orders.ts`, inside the validation loop, before subsequent items are validated. The service function must preserve this exact sequencing. If a future developer wants to change this to "validate all then deduct all," that is a separate behavioral change and must NOT be done in this refactoring.

**3. The `listProducts` filter for `minPrice`/`maxPrice` parsing.** In the current code, `parseFloat` and `isNaN` checks are done inside the route handler (they operate on query strings). In the refactored version, these checks stay in the route handler. The service receives `number | undefined`. If someone passes `?minPrice=abc`, `parseFloat("abc")` returns `NaN`, `isNaN` catches it, and the filter is not applied -- same as before.

**4. The `typeof adjustment !== "number"` check.** This validation lives in the service, not the route handler, because `req.body` provides no type guarantee. The service is the gatekeeper for this invariant.

**5. Test ordering and shared mutable state.** The tests mutate shared in-memory data (creating orders, updating stock, changing order status). Tests run in sequence within vitest and share the same app instance. The refactoring does not change any mutation semantics, so test ordering issues will not arise.

